INSERT INTO public.page_contents (page_key, title, content)
VALUES 
  ('faq', 'FAQ', '{"subtitle":"Häufig gestellte Fragen","categories":[{"title":"Tickets","emoji":"🎟️","items":[{"q":"Muss ich mein Ticket ausdrucken?","a":"Nein! Du kannst dein Ticket bequem digital auf deinem Handy vorzeigen."},{"q":"Wo finde ich meine Tickets nach dem Kauf?","a":"Du erhältst deine Tickets per E-Mail. Alternativ unter Meine Tickets auf unserer Website."},{"q":"Kann ich mein Ticket stornieren?","a":"Eine Stornierung ist leider grundsätzlich nicht möglich. Du kannst dein Ticket aber an eine andere Person weitergeben."}]},{"title":"Allgemein","emoji":"ℹ️","items":[{"q":"Wie erreiche ich euch?","a":"Am besten per E-Mail: mail@nightlifegeneration.de. Alternativ über Instagram oder unseren Support-Chat."}]},{"title":"U18","emoji":"🔞","items":[{"q":"Ab welchem Alter komme ich rein?","a":"Bei den meisten Events ist der Einlass ab 16 Jahren möglich - mit Muttizettel und volljähriger Begleitperson auch länger."},{"q":"Was ist ein Muttizettel?","a":"Eine Einverständniserklärung deiner Eltern. Du findest ihn auf unserer Website unter Muttizettel."}]}]}'),
  ('datenschutz', 'Datenschutz', '{"subtitle":"Datenschutzerklärung","sections":[{"title":"1. Verantwortlicher","body":"Verantwortlich für die Verarbeitung Ihrer personenbezogenen Daten auf dieser Website ist:\nSwaye Event & Gastro UG (haftungsbeschränkt)\nJoshua Eiffinger\nHolzhofstraße 17\n55116 Mainz\nE-Mail: info@nightlifeticket.app"},{"title":"2. Erhebung und Speicherung personenbezogener Daten","body":"Beim Aufrufen unserer Website erheben wir Informationen, die Ihr Browser automatisch an unseren Server übermittelt (IP-Adresse, Datum/Uhrzeit, URL, Referrer, Browser). Diese Daten werden zur Sicherstellung eines reibungslosen Verbindungsaufbaus verwendet. Rechtsgrundlage: Art. 6 Abs. 1 lit. f DSGVO."},{"title":"3. Weitergabe von Daten","body":"Ihre Daten werden nur an Dritte weitergegeben, wenn dies für die Vertragsabwicklung erforderlich ist (z.B. Zahlungsdienstleister, IT-Dienstleister). Eine darüber hinausgehende Weitergabe erfolgt nur mit ausdrücklicher Zustimmung."},{"title":"4. Zahlungsabwicklung","body":"Wir bieten verschiedene Zahlungsmethoden an, bei deren Nutzung Daten an die entsprechenden Zahlungsdienstleister übermittelt werden."},{"title":"5. Cookies","body":"Unsere Website verwendet Cookies. Notwendige Cookies sind für die Funktion erforderlich (Art. 6 Abs. 1 lit. f DSGVO). Für analytische Cookies holen wir Ihre Einwilligung ein (Art. 6 Abs. 1 lit. a DSGVO)."},{"title":"6. Ihre Rechte","body":"Sie haben das Recht auf Auskunft (Art. 15 DSGVO), Berichtigung (Art. 16 DSGVO), Löschung (Art. 17 DSGVO), Einschränkung (Art. 18 DSGVO), Widerspruch (Art. 21 DSGVO) und Datenübertragbarkeit (Art. 20 DSGVO)."},{"title":"7. Dauer der Datenspeicherung","body":"Wir speichern Ihre personenbezogenen Daten nur so lange, wie dies zur Erfüllung der genannten Zwecke erforderlich ist oder wie es gesetzliche Aufbewahrungspflichten vorsehen."},{"title":"8. Kontakt","body":"Bei Fragen wenden Sie sich an:\nSwaye Event & Gastro UG (haftungsbeschränkt)\nJoshua Eiffinger\nHolzhofstraße 17\n55116 Mainz\nE-Mail: info@nightlifeticket.app"}]}')
